patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..2923a8c270b2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4528,6 +4528,14 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // icmp ((~X) ^ Y) slt/ult ~X --> icmp (X ^ Y) sgt/ugt X
+  // icmp ((~X) ^ Y) sge/uge ~X --> icmp (X ^ Y) sle/ule X
+  Value *X;
+  if (match(Op1, m_Not(m_Value(X)))) {
+    Value *Xor = IC.Builder.CreateXor(A, X);
+    return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Xor, X);
+  }
+
   return nullptr;
 }

