static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
                                  InstCombinerImpl &IC) {
  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
  // Normalize xor operand as operand 0.
  CmpInst::Predicate Pred = I.getPredicate();
  if (match(Op1, m_c_Xor(m_Specific(Op0), m_Value()))) {
    std::swap(Op0, Op1);
    Pred = ICmpInst::getSwappedPredicate(Pred);
  }

  if (match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A)))) {
    // icmp (X ^ Y_NonZero) u>= X --> icmp (X ^ Y_NonZero) u> X
    // icmp (X ^ Y_NonZero) u<= X --> icmp (X ^ Y_NonZero) u< X
    // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
    // icmp (X ^ Y_NonZero) s<= X --> icmp (X ^ Y_NonZero) s< X
    CmpInst::Predicate PredOut = CmpInst::getStrictPredicate(Pred);
    if (PredOut != Pred &&
        isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
      return new ICmpInst(PredOut, Op0, Op1);

    // icmp ((~X) ^ Y) slt/ult ~X --> icmp (X ^ Y) sgt/ugt X
    // icmp ((~X) ^ Y) sge/uge ~X --> icmp (X ^ Y) sle/ule X
    Value *X;
    if (match(Op1, m_Not(m_Value(X)))) {
      Value *Xor = IC.Builder.CreateXor(A, X);
      return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Xor, X);
    }

    return nullptr;
  }

  // (~X ^ Y) <OP> ~Z  -->  (X ^ Y) <OP'> Z (where OP' is swapped(OP))
  // This handles the case where Op0 and Op1 are NOTs of different values.
  Value *X, *Z;
  if (Op0->hasOneUse() &&
      match(Op0, m_c_Xor(m_Not(m_Value(X)), m_Value(A))) &&
      match(Op1, m_Not(m_Value(Z)))) {
    Value *NewXor = IC.Builder.CreateXor(X, A);
    return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), NewXor, Z);
  }
  // Also handle the commuted case: ~Z <OP> (~X ^ Y)  -->  Z <OP'> (X ^ Y)
  if (Op1->hasOneUse() &&
      match(Op1, m_c_Xor(m_Not(m_Value(X)), m_Value(A))) &&
      match(Op0, m_Not(m_Value(Z)))) {
    Value *NewXor = IC.Builder.CreateXor(X, A);
    return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Z, NewXor);
  }

  return nullptr;
}
